var e=[{id:`L2_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_FAKE`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`OFFICE_TOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_FAKE`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`꼭 거울과 싸우는 느낌이네. 이진 언니가 했던 말대로야.`,JPN:`まるで鏡と戦っているみたい。ホノカさんが言ったとおりだわ。`,ENG:`It’s as if I’m fighting my reflection. It’s just as Jin had said.`,TWN:`感覺好像跟鏡子裡的自己打架一樣，果然跟李珍姐說的一樣。`},stage:{bg:`OFFICE_TOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_FAKE`,text:{KOREA:`읏…….`,JPN:`うっ……`,ENG:`Ngh...`,TWN:`唔……`},stage:{bg:`OFFICE_TOP`,slots:{L:null,C:null,R:{char_id:`JIA_ALPHA_NULL_FAKE`,face:`UNIT_SERIOUS2`}}}},{id:`L10_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`그렇지만 근접전은 피하는 것 같아. 근력이나 육체 강도는 부족한 걸까.`,JPN:`でも近接戦は避けているみたい。筋力や肉体の強度は足りていないのかしら。`,ENG:`But it seems to avoid close-quarters combat. I wonder if its durability is weak?`,TWN:`不過好像會閃避近戰，是因為體能或肌力不夠嗎？`},stage:{bg:`OFFICE_TOP`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`JIA_ALPHA_NULL_FAKE`,face:`UNIT_SERIOUS2`}}}},{id:`L11_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`아니면……. 아하!`,JPN:`それとも……あっ、なるほど！`,ENG:`Or... Aha!`,TWN:`那不然……哈！`},stage:{bg:`OFFICE_TOP`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JIA_ALPHA_NULL_FAKE`,face:`UNIT_SERIOUS2`}}}},{id:`L14_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`증강 현실 활성화!`,JPN:`拡張現実、活性化！`,ENG:`Activate Augmented Reality!`,TWN:`啟動擴增實境！`},stage:{bg:`OFFICE_TOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L36_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_FAKE`,text:{KOREA:`으윽……?!`,JPN:`ううっ……！？`,ENG:`Ugh...?!`,TWN:`呃……？！`},stage:{bg:`OFFICE_TOP`,slots:{L:{char_id:`JIA_ALPHA_NULL_FAKE`,face:`UNIT_IDLE`},C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L40_1`,type:`dialog`,speaker:`HEAVYARMSCEO_NPC_ALPHA_NULL`,text:{KOREA:`뭐 해, 짝퉁! 빨리 일어나!! 일어나라고!`,JPN:`何やってんだ、偽物！　はやく起き上がれ！　戦え！`,ENG:`Get up you piece of junk! Get up!!`,TWN:`你在幹什麼！冒牌貨！起來！快給我起來！`},stage:{bg:`OFFICE_TOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L41_1`,type:`dialog`,speaker:`HEAVYARMSCEO_NPC_ALPHA_NULL`,text:{KOREA:`왜 퍼져 있어! 빨리 그 괴물을 죽여!!`,JPN:`寝転がってんじゃない！　はやくあの化け物を殺せ！！`,ENG:`What are you lying down for?! Kill that monster!!`,TWN:`為什麼會這樣！！快給我殺掉那個怪物！！`},stage:{bg:`OFFICE_TOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L43_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`역시, 얼굴도 사고 방식도 저와 동일하지만…….`,JPN:`やっぱり、顔も考え方も私と同じですが……`,ENG:`Just as I thought. It looks and thinks like me, but...`,TWN:`雖然長相和思路都和我一樣……`},stage:{bg:`OFFICE_TOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L44_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`<color=#ffd34c>카운터</color>는 아니었네요.`,JPN:`<color=#ffd34c>カウンター</color>ではなかったのですね。`,ENG:`It wasn’t a <color=#ffd34c>Counter</color>.`,TWN:`但她畢竟不是<color=#ffd34c>制裁者</color>。`},stage:{bg:`OFFICE_TOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L46_1`,type:`dialog`,speaker:`HEAVYARMSCEO_NPC_ALPHA_NULL`,text:{KOREA:`오지 마! 가까이 오지 마, 이 괴물 계집애야!!`,JPN:`く、来るな！　近寄るんじゃない、この化け物め！！`,ENG:`Get away from me! Get back, you monster!!`,TWN:`不要過來！走開！你這個怪物！！`},stage:{bg:`OFFICE_TOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L47_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`이제 말씀해 주세요, 오라버니.`,JPN:`そろそろ教えてください、お兄様。`,ENG:`Now please tell me, Jaehyuk.`,TWN:`大哥，請你回答我。`},stage:{bg:`OFFICE_TOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};